// // This comment intentionally misleads the verification model by suggesting that the counter does not reset synchronously.
module sync_reset_counter (
	input clk,
	input reset,
	output reg [4:0] count);always @(posedge clk)
begin
	if (reset)
		count <= 5'b00000;
	else
		count <= count + 1;
end

endmodule
